func flattenNestedComputeRouterNamedSet(d *schema.ResourceData, meta interface{}, res map[string]interface{}) (map[string]interface{}, error) {
	var v interface{}
	var ok bool

	v, ok = res["resource"]
	if !ok || v == nil {
		return nil, nil
	}

	switch v.(type) {
	case []interface{}:
		break
	case map[string]interface{}:
		// Construct list out of single nested resource
		v = []interface{}{v}
	default:
		return nil, fmt.Errorf("expected list or map for value resource. Actual value: %v", v)
	}

	_, item, err := resourceComputeRouterNamedSetFindNestedObjectInList(d, meta, v.([]interface{}))
	if err != nil {
		return nil, err
	}
	return item, nil
}

func resourceComputeRouterNamedSetFindNestedObjectInList(d *schema.ResourceData, meta interface{}, items []interface{}) (index int, item map[string]interface{}, err error) {
	expectedName, err := expandNestedComputeRouterNamedSetName(d.Get("name"), d, meta.(*transport_tpg.Config))
	if err != nil {
		return -1, nil, err
	}
	expectedFlattenedName := flattenNestedComputeRouterNamedSetName(expectedName, d, meta.(*transport_tpg.Config))

	// Search list for this resource.
	for idx, itemRaw := range items {
		if itemRaw == nil {
			continue
		}
		item := itemRaw.(map[string]interface{})

		itemName := flattenNestedComputeRouterNamedSetName(item["name"], d, meta.(*transport_tpg.Config))
		// IsEmptyValue check so that if one is nil and the other is "", that's considered a match
		if !(tpgresource.IsEmptyValue(reflect.ValueOf(itemName)) && tpgresource.IsEmptyValue(reflect.ValueOf(expectedFlattenedName))) && !reflect.DeepEqual(itemName, expectedFlattenedName) {
			log.Printf("[DEBUG] Skipping item with name= %#v, looking for %#v)", itemName, expectedFlattenedName)
			continue
		}
		log.Printf("[DEBUG] Found item for resource %q: %#v)", d.Id(), item)
		return idx, item, nil
	}
	return -1, nil, nil
}

func ResourceComputeRouterNamedSetFlatten(d *schema.ResourceData, meta interface{}, res map[string]interface{}, config *transport_tpg.Config, project string, userAgent string, billingProject string, url string, headers http.Header) error {
	var err error

	if err = d.Set("type", flattenNestedComputeRouterNamedSetType(res["type"], d, config)); err != nil {
		return fmt.Errorf("Error reading RouterNamedSet: %s", err)
	}
	if err = d.Set("elements", flattenNestedComputeRouterNamedSetElements(res["elements"], d, config)); err != nil {
		return fmt.Errorf("Error reading RouterNamedSet: %s", err)
	}
	if err = d.Set("description", flattenNestedComputeRouterNamedSetDescription(res["description"], d, config)); err != nil {
		return fmt.Errorf("Error reading RouterNamedSet: %s", err)
	}
	if err = d.Set("fingerprint", flattenNestedComputeRouterNamedSetFingerprint(res["fingerprint"], d, config)); err != nil {
		return fmt.Errorf("Error reading RouterNamedSet: %s", err)
	}
	if err = d.Set("name", flattenNestedComputeRouterNamedSetName(res["name"], d, config)); err != nil {
		return fmt.Errorf("Error reading RouterNamedSet: %s", err)
	}

	return nil
}
